mapper.select:
SELECT * FROM SEARCH_KEYWORDS
WHERE  keyword_id = #{keywordId}
  AND  deleted_yn  = 'N'

mapper.update:
UPDATE SEARCH_KEYWORDS
SET    deleted_yn = 'Y',
       deleted_at = SYSTIMESTAMP,
       updated_by = #{deletedBy}
WHERE  keyword_id = #{keywordId}

mapper.insert:
INSERT INTO CARD_KEYWORDS (card_id, keyword_id, created_at, created_by)
SELECT #{cardId}, #{keywordId}, SYSTIMESTAMP, #{createdBy, jdbcType=NUMERIC}
FROM   DUAL
WHERE  NOT EXISTS (
    SELECT 1 FROM CARD_KEYWORDS
    WHERE  card_id    = #{cardId}
      AND  keyword_id  = #{keywordId}
      AND  deleted_yn  = 'N'
)

mapper.select:
SELECT CASE WHEN COUNT(1) > 0 THEN 1 ELSE 0 END
FROM   CARD_KEYWORDS
WHERE  card_id    = #{cardId}
  AND  keyword_id  = #{keywordId}
  AND  deleted_yn  = 'N'

SELECT DISTINCT card_id FROM CARD_KEYWORDS WHERE keyword_id IN
#{id}
AND deleted_yn = 'N'
